operations.find:
const restrictionType =
  this?.config?.type ??
  this?.config?.wallRestrictionType ??
  "sight";

/*
 * Elevation changes sight only. Movement, sound, and other
 * collision polygons continue using ordinary Foundry walls.
 */
const isSightPolygon =
  restrictionType === "sight" ||
  restrictionType === "vision";

if (isSightPolygon) {
  const viewerElevation =
    viewingElevationFromPolygon(this);

  if (viewerElevation !== null) {
    const wallDocument =
      wallDocumentFromEdge(args[0]);

    if (
      wallDocument &&
      wallHasFiniteElevation(wallDocument) &&
      !wallBlocksElevation(
        wallDocument,
        viewerElevation
      )
    ) {
      return false;
    }
  }
}

operations.replace:
const restrictionType = String(
  this?.config?.type ??
  this?.config?.wallRestrictionType ??
  "sight"
).toLowerCase();

/*
 * Elevation affects both vision polygons and movement
 * collision polygons. Sound and unrelated collision types
 * continue using ordinary Foundry wall behavior.
 */
const isElevationAwarePolygon = [
  "sight",
  "vision",
  "move",
  "movement"
].includes(restrictionType);

if (isElevationAwarePolygon) {
  const tokenElevation =
    viewingElevationFromPolygon(this);

  if (tokenElevation !== null) {
    const wallDocument =
      wallDocumentFromEdge(args[0]);

    if (
      wallDocument &&
      wallHasFiniteElevation(wallDocument) &&
      !wallBlocksElevation(
        wallDocument,
        tokenElevation
      )
    ) {
      /*
       * Returning false excludes this wall from the polygon.
       * For vision, the token can see over it. For movement,
       * the token can pass over or beneath it.
       */
      return false;
    }
  }
}
